INSERT INTO `sys_course` (`title`, `category`, `cover_url`, `video_url`, `content`, `reward_points`) VALUES 
('实验室安全规范与操作指南', '实验室安全', 'https://images.unsplash.com/photo-1532094349884-543bc11b234d?auto=format&fit=crop&w=600&q=80', NULL, '实验室是高校教学和科研的重要基地。由于实验室中经常使用各种化学药品、易燃易爆物品、剧毒物质以及各类电器设备，如果管理不善或操作不当，极易引发火灾、爆炸、中毒、触电等安全事故。\n\n一、实验室基础安全要求\n1. 进入实验室必须穿戴规定的防护服、护目镜和手套，严禁穿拖鞋、短裤进入。\n2. 实验室内严禁饮食、吸烟，不得存放个人食物。\n3. 熟悉实验室内的消防器材、洗眼器、紧急喷淋装置的位置及使用方法。\n\n二、化学危险品使用规范\n1. 危险化学品必须严格实行“双人双锁”管理，领用需做好详细记录。\n2. 挥发性、有毒气体实验必须在通风橱内进行，操作时需保持通风橱拉门在安全高度。\n3. 废弃化学试剂严禁倒入下水道，必须分类收集于专用废液桶中，贴好标签并交由专业机构处理。\n\n三、仪器设备安全\n1. 使用大型仪器设备前，必须经过专业培训并取得操作资格。\n2. 严禁私自乱拉乱接电线，设备运行期间操作人员不得擅自离开。\n3. 发现设备异常发热、异响或漏电，应立即切断电源并向管理员报告。\n\n四、应急处理预案\n1. 发生火灾时，应根据燃烧物性质选择合适的灭火器（如电器起火绝不能用水或泡沫灭火器）。\n2. 强酸强碱溅到皮肤上，应立即用大量流动清水冲洗至少15分钟，随后就医。\n3. 发生有毒气体泄漏，应立即停止实验，打开窗户，疏散人员并报警。\n\n安全无小事，防患于未然。请每位同学严格遵守实验室规章制度，保护自己和他人的生命财产安全。', 20),
